export const getProfileForUser = async (user: any): Promise<User | null> => {
    if (!user) return null;
    const { data: profile, error } = await supabase
        .from('users')
        .select('*')
        .eq('id', user.id)
        .maybeSingle();

    if (error) throw error;
    if (!profile) throw new Error("User profile not found.");
    return profile;
};

export const formatSupabaseError = (error: any): string => {
    if (!error) return "Error desconocido";
    const message = String(error.message || error.error_description || error.msg || error);

    if (message.includes("Could not find the table 'app_settings'")) {
        return `Error: Falta la tabla de configuración.\n\nEjecuta esto en el SQL Editor de Supabase:\n\nCREATE TABLE public.app_settings (id TEXT PRIMARY KEY, value TEXT);\nINSERT INTO public.app_settings (id, value) VALUES ('app_logo_url', null);\nALTER TABLE public.app_settings ENABLE ROW LEVEL SECURITY;\nCREATE POLICY "Permitir lectura publica" ON public.app_settings FOR SELECT USING (true);\nCREATE POLICY "Permitir a admins actualizar" ON public.app_settings FOR UPDATE USING ((SELECT role FROM public.users WHERE id = auth.uid()) = 'admin');`;
    }

    if (message.includes('Bucket not found') && message.includes('app-assets')) {
        return `Error: El bucket 'app-assets' no existe.\n\nCrea un bucket llamado 'app-assets' en Supabase Storage y hazlo PÚBLICO.`;
    }

    return message;
};

