import { User, UserRole, Property, Task, DailyLog, Notification, TaskStatus } from '@/types';

const NavItem = ({ icon: Icon, label, isActive, onClick }: any) => (
  <li>
    <button
      onClick={onClick}
      className={`flex items-center w-full p-3 rounded-lg text-left transition-colors ${
        isActive ? 'bg-orange-500 text-white shadow' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-600'
      }`}
    >
