      init();
    } else {
      // Intenta cargar el logo incluso si no hay sesión para el Login
      supabase.from('app_settings').select('*').eq('id', 'app_logo_url').maybeSingle()
        .then(({ data }) => { if (data) setAppLogoUrl(data.value); });
      setCurrentUser(null);
      setLoading(false);
    }
  }, [session, fetchData]);

  const handleUpdateLogo = async (url: string) => {
    try {
      const { error } = await supabase
        .from('app_settings')
        .upsert({ id: 'app_logo_url', value: url });
      if (error) throw error;
      setAppLogoUrl(url);
      return true;
    } catch (err) {
      alert(formatSupabaseError(err));
      return false;
    }
  };

  const renderContent = () => {
    if (selectedPropertyId) {
      const prop = properties.find(p => p.id === selectedPropertyId);
      if (prop) return (
        <PropertyDetails
