        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          currentUser={currentUser} 
          logoUrl={appLogoUrl}
          onLogout={() => supabase.auth.signOut()} 
          unreadCount={notifications.filter(n => !n.readBy.includes(currentUser.id)).length}
          onToggleNotifications={() => setIsNotificationsOpen(true)}
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderContent()}
        </main>
      </div>

      {isNotificationsOpen && <NotificationPanel notifications={notifications} currentUser={currentUser} onClose={() => setIsNotificationsOpen(false)} onMarkAsRead={() => {}} />}
    </div>
  );
};

export default App;

