const LogoUploadCard = ({ currentLogoUrl, onUpdateLogo }: { currentLogoUrl: string | null, onUpdateLogo: (url: string) => Promise<boolean> }) => {
    const [isUploading, setIsUploading] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!e.target.files || !e.target.files[0]) return;

        setIsUploading(true);
        const file = e.target.files[0];
        const fileExt = file.name.split('.').pop();
        const fileName = `logo-${Date.now()}.${fileExt}`;
        const filePath = `public/${fileName}`;

        try {
            const { error: uploadError } = await supabase.storage
                .from('app-assets')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: urlData } = supabase.storage
                .from('app-assets')
                .getPublicUrl(filePath);

            await onUpdateLogo(urlData.publicUrl);
        } catch (error: any) {
            alert("Error al subir el logo: " + error.message);
        } finally {
            setIsUploading(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    return (
        <div className="bg-white p-6 rounded-lg shadow border border-orange-100">
            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Logo de la Empresa</h3>
