                    ) : (
                        <div className="text-center text-slate-400">
                            <PhotoIcon className="mx-auto h-6 w-6" />
                            <span className="text-[10px]">Sin logo cargado</span>
                        </div>
                    )}
                </div>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={handleFileChange} 
                />
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    disabled={isUploading}
                    className="w-full py-2 px-4 bg-orange-50 text-orange-600 border border-orange-200 rounded-md text-sm font-bold hover:bg-orange-100 transition-colors disabled:opacity-50"
                >
                    {isUploading ? 'Subiendo...' : 'Subir desde ordenador'}
                </button>
                <p className="text-[10px] text-slate-400 text-center">Recomendado: PNG horizontal con fondo transparente</p>
            </div>
        </div>
    );
};

