            </div>

            {/* Fila 2: Visitas, Tareas y Calculadora */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard title="Visitas Programadas" value={totalVisits} icon={<CalendarDaysIcon className="h-5 w-5" />} color="bg-orange-500" />
                <StatCard title="Tareas Pendientes" value={pendingTasks} icon={<ClipboardDocumentListIcon className="h-5 w-5" />} color="bg-yellow-500" />
                <CalculatorCard />
            </div>

            {/* Fila 3: Listas Detalladas */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
                {/* Tareas Recientes */}
                <div className="lg:col-span-2 bg-white rounded-lg shadow-sm border border-slate-100 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-50">
                        <h2 className="text-sm font-bold text-slate-800">Tareas Recientes</h2>
                    </div>
                    <div className="divide-y divide-slate-50">
                        {tasks.slice(0, 5).map((task: any) => {
                            const property = properties.find((p: any) => p.id === task.propertyId);
                            const worker = users.find((u: any) => u.id === (task.workerIds?.[0] || task.workerId));
                            return (
                                <div key={task.id} className="px-6 py-4 flex items-start space-x-4 hover:bg-slate-50 transition-colors">
                                    <div className={`mt-1.5 h-3 w-3 rounded-full flex-shrink-0 ${task.status === TaskStatus.COMPLETED ? 'bg-green-400' : 'bg-yellow-400'}`}></div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-[13px] font-medium text-slate-700">{task.description}</p>
                                        <p className="text-[11px] text-slate-400 mt-0.5">Propiedad: {property ? `ID ${property.propertyIdNumber} ${property.name}` : 'No asignada'}</p>
                                        <p className="text-[11px] text-slate-400">Asignado a: {worker?.name || '---'}</p>
                                    </div>
                                </div>
                            );
                        })}
                        {tasks.length === 0 && <p className="px-6 py-8 text-center text-slate-400 text-sm italic">No hay tareas registradas.</p>}
                    </div>
                </div>

                {/* Próximas Visitas */}
                <div className="bg-white rounded-lg shadow-sm border border-slate-100 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-50">
                        <h2 className="text-sm font-bold text-slate-800">Próximas Visitas</h2>
                    </div>
                    <div className="divide-y divide-slate-50">
                        {visits.slice(0, 5).map((visit: any) => {
                            const property = properties.find((p: any) => p.id === visit.propertyId);
                            return (
                                <div 
                                    key={visit.id} 
                                    onClick={() => onSelectVisit(visit.id)}
                                    className="px-6 py-4 flex items-center justify-between cursor-pointer hover:bg-slate-50 transition-colors"
                                >
                                    <div className="flex items-start space-x-3 min-w-0">
                                        <div className="mt-1 text-slate-300">
                                            <CalendarIcon className="h-5 w-5" />
                                        </div>
                                        <div className="min-w-0">
                                            <p className="text-[13px] font-bold text-slate-800 truncate">{visit.clientName}</p>
                                            <p className="text-[11px] text-slate-500">{visit.date} a las {visit.time}</p>
                                            <p className="text-[11px] text-slate-400 truncate">{property ? `ID ${property.propertyIdNumber} ${property.name}` : ''}</p>
                                        </div>
                                    </div>
                                    <ChevronRightIcon className="h-4 w-4 text-slate-300 flex-shrink-0" />
                                </div>
                            );
                        })}
                        {visits.length === 0 && <p className="px-6 py-8 text-center text-slate-400 text-sm italic">No hay visitas programadas.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { supabase, getProfileForUser, formatSupabaseError } from '@/supabaseClient';
import { Session } from '@supabase/supabase-js';

// Components
import Login from '@/components/Login';
import Header from '@/components/Header';
import Dashboard from '@/components/Dashboard';
import PropertyList from '@/components/PropertyList';
import PropertyDetails from '@/components/PropertyDetails';
import PropertyForm from '@/components/PropertyForm';
import ManageUsers from '@/components/ManageUsers';
import TrainingCenter from '@/components/TrainingCenter';
import Calendar from '@/components/Calendar';
import CaptacionesList from '@/components/CaptacionesList';
import CaptacionDetails from '@/components/CaptacionDetails';
import BinnacleView from '@/components/BinnacleView';
import Reports from '@/components/Reports';
import Formatos from '@/components/Formatos';
import Settings from '@/components/Settings';
import NetworkErrorOverlay from '@/components/NetworkErrorOverlay';
import NotificationPanel from '@/components/NotificationPanel';
import ConfirmationModal from '@/components/ConfirmationModal';

// Icons
import { CogIcon } from '@/components/icons/CogIcon';
import { BuildingOfficeIcon } from '@/components/icons/BuildingOfficeIcon';
import { CalendarDaysIcon } from '@/components/icons/CalendarDaysIcon';
import { ClipboardDocumentCheckIcon } from '@/components/icons/ClipboardDocumentCheckIcon';
import { ClipboardDocumentListIcon } from "@/components/icons/ClipboardDocumentListIcon";
import { UserIcon } from '@/components/icons/UserIcon';
import { AcademicCapIcon } from '@/components/icons/AcademicCapIcon';
import { DocumentTextIcon } from '@/components/icons/DocumentTextIcon';

import { User, UserRole, Property, Task, DailyLog, Notification, TaskStatus } from '@/types';

const NavItem = ({ icon: Icon, label, isActive, onClick }: any) => (
  <li>
    <button
      onClick={onClick}
      className={`flex items-center w-full px-4 py-3 rounded-lg text-left transition-all duration-200 ${
        isActive 
          ? 'bg-orange-500 text-white shadow-md font-bold' 
          : 'text-slate-600 hover:bg-slate-50 hover:text-orange-600'
      }`}
    >
      <span className="h-6 w-6"><Icon className={isActive ? "text-white" : "text-slate-500"} /></span>
      <span className="ml-3 text-[14px]">{label}</span>
    </button>
  </li>
);

const App = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [appLogoUrl, setAppLogoUrl] = useState<string | null>(null);

  // App Data State
  const [users, setUsers] = useState<User[]>([]);
  const [properties, setProperties] = useState<Property[]>([]);
  const [visits, setVisits] = useState<any[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [dailyLogs, setDailyLogs] = useState<DailyLog[]>([]);
  const [captaciones, setCaptaciones] = useState<any[]>([]);
  const [resources, setResources] = useState<any[]>([]);
  const [formats, setFormats] = useState<any[]>([]);

  // UI State
  const [activeView, setActiveView] = useState('dashboard');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [selectedCaptacionId, setSelectedCaptacionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);

  // Property CRUD State
  const [isPropertyModalOpen, setIsPropertyModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [propertyToDelete, setPropertyToDelete] = useState<Property | null>(null);

  const fetchData = useCallback(async () => {
    try {
      const [
        { data: usersData },
        { data: propData },
        { data: visitData },
        { data: taskData },
        { data: notifData },
        { data: logsData },
        { data: captData },
        { data: resData },
        { data: formatData },
        { data: settingsData }
      ] = await Promise.all([
        supabase.from('users').select('*'),
        supabase.from('properties').select('*').order('created_at', { ascending: false }),
        supabase.from('visits').select('*'),
        supabase.from('tasks').select('*'),
        supabase.from('notifications').select('*'),
        supabase.from('daily_logs').select('*'),
        supabase.from('captaciones').select('*'),
        supabase.from('training_resources').select('*'),
        supabase.from('formats').select('*'),
        supabase.from('app_settings').select('*').eq('id', 'app_logo_url').maybeSingle()
      ]);

      setUsers(usersData || []);
      setProperties(propData || []);
      setVisits(visitData || []);
      setTasks(taskData || []);
      setNotifications((notifData || []).map(n => ({ ...n, timestamp: new Date(n.timestamp) })));
      setDailyLogs(logsData || []);
      setCaptaciones(captData || []);
      setResources(resData || []);
      setFormats(formatData || []);
      if (settingsData) setAppLogoUrl(settingsData.value);
      setError(null);
    } catch (err: any) {
      console.error("Error fetching data:", err);
      setError(formatSupabaseError(err));
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (!session) setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      const init = async () => {
        setLoading(true);
        try {
          const profile = await getProfileForUser(session.user);
          setCurrentUser(profile);
          await fetchData();
        } catch (err) {
          setError(formatSupabaseError(err));
        } finally {
          setLoading(false);
        }
      };
      init();
    } else {
      supabase.from('app_settings').select('*').eq('id', 'app_logo_url').maybeSingle()
        .then(({ data }) => { if (data) setAppLogoUrl(data.value); });
      setCurrentUser(null);
      setLoading(false);
    }
  }, [session, fetchData]);

  // Property Handlers
  const handleOpenPropertyModal = (property: Property | null = null) => {
    setEditingProperty(property);
    setIsPropertyModalOpen(true);
  };

  const handleSaveProperty = async (propertyData: any) => {
    try {
      const dataToSave = { 
        ...propertyData, 
        created_by: editingProperty ? editingProperty.created_by : currentUser?.id 
      };

      const { error } = await supabase
        .from('properties')
        .upsert(dataToSave);

      if (error) throw error;

      setIsPropertyModalOpen(false);
      setEditingProperty(null);
      await fetchData();
    } catch (err: any) {
      alert("Error al guardar propiedad: " + formatSupabaseError(err));
    }
  };

  const handleDeleteProperty = async () => {
    if (!propertyToDelete) return;
    try {
      const { error } = await supabase
        .from('properties')
        .delete()
        .eq('id', propertyToDelete.id);

      if (error) throw error;
      setPropertyToDelete(null);
      await fetchData();
    } catch (err: any) {
      alert("Error al eliminar propiedad: " + formatSupabaseError(err));
    }
  };

  const handleUpdateSetting = async (id: string, value: string) => {
    try {
      const { error } = await supabase.from('app_settings').upsert({ id, value });
      if (error) throw error;
      if (id === 'app_logo_url') setAppLogoUrl(value);
      return true;
    } catch (err) {
      alert(formatSupabaseError(err));
      return false;
    }
  };

  const renderContent = () => {
    if (selectedPropertyId) {
      const prop = properties.find(p => p.id === selectedPropertyId);
      if (prop) return (
        <PropertyDetails
          property={prop}
          visits={visits.filter(v => v.propertyId === prop.id)}
          tasks={tasks.filter(t => t.propertyId === prop.id)}
          users={users}
          currentUser={currentUser!}
          onBack={() => setSelectedPropertyId(null)}
          onSelectVisit={() => {}} 
          onOpenAddVisitModalForProperty={() => {}} 
          onCompleteTask={async (id: string) => {
            await supabase.from('tasks').update({ status: TaskStatus.COMPLETED }).eq('id', id);
            fetchData();
          }}
          onOpenVisitEditor={() => {}}
        />
      );
    }

    if (selectedCaptacionId) {
      const capt = captaciones.find(c => c.id === selectedCaptacionId);
      if (capt) return (
        <CaptacionDetails
          captacion={capt}
          currentUser={currentUser!}
          onBack={() => setSelectedCaptacionId(null)}
          onEdit={() => {}}
          onDelete={() => {}}
        />
      );
    }

    switch (activeView) {
      case 'properties':
        return (
          <PropertyList 
            properties={properties} 
            currentUser={currentUser!} 
            users={users} 
            onSelectProperty={setSelectedPropertyId} 
            onAddProperty={() => handleOpenPropertyModal(null)} 
            onEditProperty={handleOpenPropertyModal} 
            onDeleteProperty={setPropertyToDelete} 
          />
        );
      case 'calendar':
        return <Calendar currentUser={currentUser!} visits={visits} calendarEvents={[]} tasks={tasks} properties={properties} users={users} onSelectVisit={() => {}} onOpenCalendarActionModal={() => {}} onSelectItem={() => {}} />;
      case 'captaciones':
        return <CaptacionesList captaciones={captaciones} onSelectCaptacion={setSelectedCaptacionId} onAddCaptacion={() => {}} />;
      case 'binnacle':
        return <BinnacleView dailyLogs={dailyLogs} users={users} currentUser={currentUser!} onDeleteLog={() => {}} onAddDailyLog={async () => true} />;
      case 'reports':
        return <Reports properties={properties} visits={visits} users={users} />;
      case 'users':
        return <ManageUsers users={users} currentUser={currentUser!} onAddUser={()=>{}} onUpdateUser={()=>{}} onDeleteUser={()=>{}} />;
      case 'training':
        return <TrainingCenter currentUser={currentUser!} resources={resources} users={users} onAddResource={()=>{}} onUpdateResource={()=>{}} onDeleteResource={()=>{}} onMarkAsViewed={()=>{}} />;
      case 'formatos':
        return <Formatos currentUser={currentUser!} formats={formats} onAddFormat={()=>{}} onEditFormat={()=>{}} onDeleteFormat={()=>{}} />;
      case 'settings':
        return <Settings currentSettings={{ app_logo_url: appLogoUrl }} onUpdateSetting={handleUpdateSetting} />;
      case 'dashboard':
      default:
        return <Dashboard 
          currentUser={currentUser!} 
          properties={properties} 
          visits={visits} 
          users={users} 
          tasks={tasks} 
          dailyLogs={dailyLogs} 
          onAddDailyLog={async () => true} 
          onGoToTaskProperty={setSelectedPropertyId} 
          onSelectVisit={() => {}} 
          onOpenAddVisitModal={() => {}} 
          onCompleteTask={() => {}} 
          onOpenVisitEditor={() => {}} 
        />;
    }
  };

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-slate-50 font-medium text-slate-600">Cargando Aquivivir...</div>;
  if (error && !session) return <NetworkErrorOverlay message={error} />;
  if (!session || !currentUser) return <Login logoUrl={appLogoUrl || undefined} />;

  return (
    <div className="min-h-screen flex bg-slate-100">
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 flex-shrink-0">
        <div className="p-6 mb-4">
          {appLogoUrl ? (
            <img src={appLogoUrl} alt="Logo" className="h-10 w-auto object-contain" />
          ) : (
            <h1 className="text-2xl font-bold text-orange-500">Aquivivir</h1>
          )}
        </div>
        <nav className="flex-1 px-4 pb-4 overflow-y-auto">
          <ul className="space-y-1.5">
            <NavItem icon={CogIcon} label="Dashboard" isActive={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} />
            <NavItem icon={BuildingOfficeIcon} label="Propiedades" isActive={activeView === 'properties'} onClick={() => setActiveView('properties')} />
            <NavItem icon={CalendarDaysIcon} label="Calendario" isActive={activeView === 'calendar'} onClick={() => setActiveView('calendar')} />
            <NavItem icon={ClipboardDocumentCheckIcon} label="Captaciones" isActive={activeView === 'captaciones'} onClick={() => setActiveView('captaciones')} />
            <NavItem icon={ClipboardDocumentListIcon} label="Bitácora" isActive={activeView === 'binnacle'} onClick={() => setActiveView('binnacle')} />
            {currentUser.role === UserRole.ADMIN && (
              <>
                <NavItem icon={CogIcon} label="Reportes" isActive={activeView === 'reports'} onClick={() => setActiveView('reports')} />
                <NavItem icon={UserIcon} label="Usuarios" isActive={activeView === 'users'} onClick={() => setActiveView('users')} />
              </>
            )}
            <NavItem icon={AcademicCapIcon} label="Capacitaciones" isActive={activeView === 'training'} onClick={() => setActiveView('training')} />
            <NavItem icon={DocumentTextIcon} label="Formatos" isActive={activeView === 'formatos'} onClick={() => setActiveView('formatos')} />
            {currentUser.role === UserRole.ADMIN && (
              <NavItem icon={CogIcon} label="Ajustes" isActive={activeView === 'settings'} onClick={() => setActiveView('settings')} />
            )}
          </ul>
        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          currentUser={currentUser} 
          logoUrl={appLogoUrl}
          onLogout={() => supabase.auth.signOut()} 
          unreadCount={notifications.filter(n => !n.readBy.includes(currentUser.id)).length}
          onToggleNotifications={() => setIsNotificationsOpen(true)}
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderContent()}
        </main>
      </div>

      {isNotificationsOpen && <NotificationPanel notifications={notifications} currentUser={currentUser} onClose={() => setIsNotificationsOpen(false)} onMarkAsRead={() => {}} />}

      {/* Property Modal */}
      {isPropertyModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4 overflow-y-auto">
          <div className="max-w-4xl w-full my-8">
            <PropertyForm 
              initialData={editingProperty} 
              workers={users.filter(u => u.role === UserRole.WORKER)}
              onSubmit={handleSaveProperty} 
              onCancel={() => { setIsPropertyModalOpen(false); setEditingProperty(null); }} 
            />
          </div>
        </div>
      )}

      {/* Delete Confirmation */}
      {propertyToDelete && (
        <ConfirmationModal 
          title="Eliminar Propiedad"
          message={`¿Estás seguro de que deseas eliminar "${propertyToDelete.name}"? Esta acción no se puede deshacer.`}
          onConfirm={handleDeleteProperty}
          onCancel={() => setPropertyToDelete(null)}
          confirmButtonText="Eliminar"
        />
      )}
    </div>
  );
};

export default App;

