import { jsx as _jsx, jsxs as _jsxs, Fragment as _Fragment } from "react/jsx-runtime";
import React, { useState, useMemo } from 'react';
import { UserRole, TaskStatus, PropertySaleStatus, Currency } from '@/types';
import { BuildingOfficeIcon } from '@/components/icons/BuildingOfficeIcon';
import { ClipboardDocumentListIcon } from '@/components/icons/ClipboardDocumentListIcon';
import { CalendarDaysIcon } from '@/components/icons/CalendarDaysIcon';
import { PlusIcon } from '@/components/icons/PlusIcon';
import { UsersIcon } from '@/components/icons/UsersIcon';
import { TagIcon } from '@/components/icons/TagIcon';
import { ChevronRightIcon } from "@/components/icons/ChevronRightIcon";
import { CalendarIcon } from "@/components/icons/CalendarIcon";

const CalculatorCard = () => {
    const [amount, setAmount] = useState('');
    const [currency, setCurrency] = useState('USD');
    const handleAmountChange = (e: any) => { if (/^\d*\.?\d*$/.test(e.target.value)) setAmount(e.target.value); };
    const numericAmount = parseFloat(amount) || 0;

    const formatCurrency = (v: number) => new Intl.NumberFormat(currency === 'USD' ? 'en-US' : 'es-PE', { 
        style: 'currency', 
        currency 
    }).format(v);

    return (
        <div className="bg-white p-5 rounded-lg shadow-sm border border-slate-100 flex flex-col h-full">
            <h3 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-4">Calculadora de Impuestos</h3>
            <div className="space-y-4 flex-1">
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <span className="text-slate-400 text-sm">{currency === 'USD' ? '$' : 'S/'}</span>
                    </div>
                    <input 
                        type="text" 
                        className="block w-full pl-8 pr-16 py-2 text-sm bg-slate-50 border-transparent rounded-md focus:ring-0 focus:bg-white transition-colors" 
                        placeholder="0.00" 
                        value={amount} 
                        onChange={handleAmountChange} 
                        inputMode="decimal" 
                    />
                    <div className="absolute inset-y-0 right-0 flex items-center">
                        <select 
                            className="h-full py-0 pl-2 pr-7 border-transparent bg-transparent text-slate-500 text-xs font-bold rounded-md focus:ring-0" 
                            value={currency} 
                            onChange={(e) => setCurrency(e.target.value)}
                        >
                            <option>USD</option>
                            <option>PEN</option>
                        </select>
                    </div>
                </div>
                <div className="space-y-3 pt-2">
                    <div className="flex justify-between items-center text-sm">
                        <span className="text-slate-500">Alcabala</span>
                        <span className="font-bold text-slate-800">{formatCurrency(numericAmount * 0.03)}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm">
                        <span className="text-slate-500">Renta</span>
                        <span className="font-bold text-slate-800">{formatCurrency(numericAmount * 0.05)}</span>
                    </div>
                </div>
            </div>
            <div className="mt-4 pt-2 flex justify-end">
                <button 
                    onClick={() => setAmount('')}
                    className="text-[10px] font-bold text-orange-500 hover:text-orange-600 uppercase tracking-widest"
                >
                    Limpiar
                </button>
            </div>
        </div>
    );
};

const Dashboard = ({ currentUser, properties, visits, users, tasks, onOpenAddVisitModal, onSelectVisit }: any) => {
    const isCurrentUserAdmin = currentUser.role === UserRole.ADMIN;

    // Stats con normalización de strings para asegurar que se cuenten todas las propiedades
    const availableProperties = properties.filter((p: any) => {
        const status = String(p.status || '').toLowerCase();
        return status === 'disponible' || status === 'available' || status === String(PropertySaleStatus.AVAILABLE).toLowerCase();
    }).length;

    const soldProperties = properties.filter((p: any) => {
        const status = String(p.status || '').toLowerCase();
        return status === 'vendido' || status === 'sold' || status === String(PropertySaleStatus.SOLD).toLowerCase();
    }).length;

    const activeWorkers = users.filter((u: any) => u.role === UserRole.WORKER).length;
    const totalVisits = visits.length;
    const pendingTasks = tasks.filter((t: any) => t.status === TaskStatus.PENDING).length;

    const StatCard = ({ title, value, icon, color }: any) => (
        <div className="bg-white p-5 rounded-lg shadow-sm border border-slate-100 flex items-center">
            <div className={`p-2.5 rounded-lg ${color} bg-opacity-10`}>
                <div className={color.replace('bg-', 'text-')}>{icon}</div>
            </div>
            <div className="ml-4">
                <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">{title}</p>
                <p className="text-2xl font-bold text-slate-800 leading-tight">{value}</p>
            </div>
        </div>
    );

    return (
        <div className="max-w-[1600px] mx-auto space-y-6">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">Dashboard</h1>
                    <p className="text-sm text-slate-500">Bienvenido de nuevo, {currentUser.name || 'admin'}.</p>
                </div>
                {isCurrentUserAdmin && (
                    <button 
                        onClick={onOpenAddVisitModal} 
                        className="inline-flex items-center px-4 py-2 bg-orange-500 text-white rounded-md text-xs font-bold shadow hover:bg-orange-600 transition"
                    >
                        <PlusIcon className="h-4 w-4 mr-2" /> Generar Visita
                    </button>
                )}
            </div>

            {/* Fila 1: Métricas Principales */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard title="Propiedades Disponibles" value={availableProperties} icon={<BuildingOfficeIcon className="h-5 w-5" />} color="bg-green-500" />
                <StatCard title="Propiedades Vendidas" value={soldProperties} icon={<TagIcon className="h-5 w-5" />} color="bg-red-500" />
                <StatCard title="Trabajadores Activos" value={activeWorkers} icon={<UsersIcon className="h-5 w-5" />} color="bg-indigo-500" />
            </div>

            {/* Fila 2: Visitas, Tareas y Calculadora */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard title="Visitas Programadas" value={totalVisits} icon={<CalendarDaysIcon className="h-5 w-5" />} color="bg-orange-500" />
                <StatCard title="Tareas Pendientes" value={pendingTasks} icon={<ClipboardDocumentListIcon className="h-5 w-5" />} color="bg-yellow-500" />
                <CalculatorCard />
            </div>

            {/* Fila 3: Listas Detalladas */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
                {/* Tareas Recientes */}
                <div className="lg:col-span-2 bg-white rounded-lg shadow-sm border border-slate-100 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-50">
                        <h2 className="text-sm font-bold text-slate-800">Tareas Recientes</h2>
                    </div>
                    <div className="divide-y divide-slate-50">
                        {tasks.slice(0, 5).map((task: any) => {
                            const property = properties.find((p: any) => p.id === task.propertyId);
                            const worker = users.find((u: any) => u.id === (task.workerIds?.[0] || task.workerId));
                            return (
                                <div key={task.id} className="px-6 py-4 flex items-start space-x-4 hover:bg-slate-50 transition-colors">
                                    <div className={`mt-1.5 h-3 w-3 rounded-full flex-shrink-0 ${task.status === TaskStatus.COMPLETED ? 'bg-green-400' : 'bg-yellow-400'}`}></div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-[13px] font-medium text-slate-700">{task.description}</p>
                                        <p className="text-[11px] text-slate-400 mt-0.5">Propiedad: {property ? `ID ${property.propertyIdNumber} ${property.name}` : 'No asignada'}</p>
                                        <p className="text-[11px] text-slate-400">Asignado a: {worker?.name || '---'}</p>
                                    </div>
                                </div>
                            );
                        })}
                        {tasks.length === 0 && <p className="px-6 py-8 text-center text-slate-400 text-sm italic">No hay tareas registradas.</p>}
                    </div>
                </div>

                {/* Próximas Visitas */}
                <div className="bg-white rounded-lg shadow-sm border border-slate-100 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-50">
                        <h2 className="text-sm font-bold text-slate-800">Próximas Visitas</h2>
                    </div>
                    <div className="divide-y divide-slate-50">
                        {visits.slice(0, 5).map((visit: any) => {
                            const property = properties.find((p: any) => p.id === visit.propertyId);
                            return (
                                <div 
                                    key={visit.id} 
                                    onClick={() => onSelectVisit(visit.id)}
                                    className="px-6 py-4 flex items-center justify-between cursor-pointer hover:bg-slate-50 transition-colors"
                                >
                                    <div className="flex items-start space-x-3 min-w-0">
                                        <div className="mt-1 text-slate-300">
                                            <CalendarIcon className="h-5 w-5" />
                                        </div>
                                        <div className="min-w-0">
                                            <p className="text-[13px] font-bold text-slate-800 truncate">{visit.clientName}</p>
                                            <p className="text-[11px] text-slate-500">{visit.date} a las {visit.time}</p>
                                            <p className="text-[11px] text-slate-400 truncate">{property ? `ID ${property.propertyIdNumber} ${property.name}` : ''}</p>
                                        </div>
                                    </div>
                                    <ChevronRightIcon className="h-4 w-4 text-slate-300 flex-shrink-0" />
                                </div>
                            );
                        })}
                        {visits.length === 0 && <p className="px-6 py-8 text-center text-slate-400 text-sm italic">No hay visitas programadas.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
